import {
    useSignAndExecuteTransaction,
 //   useIotaClient
} from '@iota/dapp-kit';
import { useState } from 'react';
import { Transaction } from '@iota/iota-sdk/transactions';
import { FormRow, CheckboxSection/*, TextInput, TextArea */} from './MoveFormsStyleHelper.tsx';
import { moveTarget, submitTx } from './MoveFormsTransactionHelper.tsx';


export function CreateContainerForm({ address }: { address: string }) {
  const { mutate: signAndExecuteTransaction } = useSignAndExecuteTransaction();
  const [digest, setDigest] = useState('');

  const [form, setForm] = useState({
    externalId: '',
    name: '',
    description: '',
    content: '',
    publicUpdate: true,
    publicAttach: true,
    publicCreateType: true,
    publicPublish: true,
    eventCreate: true,
    eventPublish: true,
    eventAttach: true,
    eventAdd: true,
    eventRemove: true,
    eventUpdate: true,
  });

  const toggle = (key: keyof typeof form) =>
    setForm((f) => ({ ...f, [key]: !f[key] }));

  const submit = () => {
    const tx = new Transaction();

    tx.moveCall({
      target: moveTarget('create_container'),
      arguments: [
        tx.pure.string(form.externalId),
        tx.pure.string(form.name),
        tx.pure.string(form.description),
        tx.pure.string(form.content),
        tx.pure.bool(form.publicUpdate),
        tx.pure.bool(form.publicAttach),
        tx.pure.bool(form.publicCreateType),
        tx.pure.bool(form.publicPublish),
        tx.pure.bool(form.eventCreate),
        tx.pure.bool(form.eventPublish),
        tx.pure.bool(form.eventAttach),
        tx.pure.bool(form.eventAdd),
        tx.pure.bool(form.eventRemove),
        tx.pure.bool(form.eventUpdate),
      ],
    });

    submitTx(signAndExecuteTransaction, tx, address, setDigest);
  };

  return (
    <div className="d-flex justify-content-center mt-4">
      <div className="w-100" style={{ maxWidth: 560 }}>
        <h5 className="text-center mb-4">Create Container</h5>

        <FormRow label="External ID">
          <input
            className="form-control form-control-sm rounded-3"
            value={form.externalId}
            onChange={(e) =>
              setForm({ ...form, externalId: e.target.value })
            }
          />
        </FormRow>

        <FormRow label="Name">
          <input
            className="form-control form-control-sm rounded-3"
            value={form.name}
            onChange={(e) =>
              setForm({ ...form, name: e.target.value })
            }
          />
        </FormRow>

        <FormRow label="Description">
          <input
            className="form-control form-control-sm rounded-3"
            value={form.description}
            onChange={(e) =>
              setForm({ ...form, description: e.target.value })
            }
          />
        </FormRow>

        <FormRow label="Content">
          <textarea
            className="form-control form-control-sm rounded-3"
            rows={4}
            value={form.content}
            onChange={(e) =>
              setForm({ ...form, content: e.target.value })
            }
          />
        </FormRow>

        <CheckboxSection
          title="Permissions"
          form={form}
          toggle={toggle}
          items={[
            ['publicUpdate', 'Public update container'],
            ['publicAttach', 'Public attach container child'],
            ['publicCreateType', 'Public create data type'],
            ['publicPublish', 'Public publish data item'],
          ]}
        />

        <CheckboxSection
          title="Events"
          form={form}
          toggle={toggle}
          items={[
            ['eventCreate', 'Emit create event'],
            ['eventPublish', 'Emit publish event'],
            ['eventAttach', 'Emit attach event'],
            ['eventAdd', 'Emit add-owner event'],
            ['eventRemove', 'Emit remove-owner event'],
            ['eventUpdate', 'Emit update event'],
          ]}
        />

        <div className="text-center mt-4">
          <button
            className="btn btn-outline-primary btn-sm px-4"
            onClick={submit}
          >
            Create Container
          </button>
        </div>

        {digest && (
          <div className="text-center small mt-3">
            Digest: {digest}
          </div>
        )}
      </div>
    </div>
  );
}
